"""Capture Court

A round of verdicts on lambda CAPTURE semantics: what a CLOSURE actually is, the difference between capturing a variable BY VALUE (a frozen private copy) and BY REFERENCE (a live link back to the original), what [=] and [&] capture by default, when a lambda needs no capture list at all, what an INIT-CAPTURE computes, and the single most dangerous capture mistake in C++ -- a reference capture that outlives the variable it refers to, tied directly to the dangling-pointer danger covered earlier in the course. No full programs to compile here -- every question is a decision or a definition, built from a short code fragment.
"""
import json, sys

# -- Crypto / obfuscation --
_KEY_A = "f77e1eb8cf6c783f644eb95334d0348d1ea2c3638743d430392f2a04df03f47b"
_KEY_B = "01a63ebd91d3bc16bceecac1cde68f0721f837dbb93584a6112f3e64e7eec185"
import base64 as _b64, hashlib as _hl, hmac as _hm, json as _js, zlib as _zl

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000

# Split runtime key. This is obfuscation only; do not treat it as a secret.
def _xor_bytes(a, b):
    return bytes(x ^ y for x, y in zip(a, b))

def _runtime_key():
    return _xor_bytes(bytes.fromhex(_KEY_A), bytes.fromhex(_KEY_B))

def _derive_key(answers):
    return _hl.pbkdf2_hmac("sha256", "|".join(answers).encode(), _SALT, _KDF_ITERS)

def _stream(key, length):
    ks, i = b"", 0
    while len(ks) < length:
        ks += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return ks[:length]

def _decrypt(blob_hex, answers):
    blob    = bytes.fromhex(blob_hex)
    key     = _derive_key(answers)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    return bytes(a ^ b for a, b in zip(ct, _stream(key, len(ct)))).decode()

def _item_key(label):
    return _hm.new(_runtime_key(), label.encode(), _hl.sha256).digest()

def _open_secret(blob_text, label):
    try:
        blob = _b64.b85decode(blob_text.encode())
        key = _item_key(label)
        ct, mac = blob[:-32], blob[-32:]
        if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
            return None
        pt = _xor_bytes(ct, _stream(key, len(ct)))
        data = _js.loads(_zl.decompress(pt).decode())
        return data if isinstance(data, dict) else None
    except Exception:
        return None

